{"content":"1: import type { EntityRestInterface } from "../worker/rest/EntityRestClient"
2: import type { RootInstance } from "../entities/sys/TypeRefs.js"
3: import { RootInstanceTypeRef } from "../entities/sys/TypeRefs.js"
4: import { CUSTOM_MIN_ID, firstBiggerThanSecond, GENERATED_MIN_ID, getElementId, getLetId, RANGE_ITEM_LIMIT } from "./utils/EntityUtils"
5: import { Type, ValueType } from "./EntityConstants"
6: import { last, TypeRef } from "@tutao/tutanota-utils"
7: import { resolveTypeReference } from "./EntityFunctions"
8: import type { ElementEntity, ListElementEntity, SomeEntity } from "./EntityTypes"
9: import { downcast } from "@tutao/tutanota-utils"
10: import { EntityRestClientSetupOptions } from "../worker/rest/EntityRestClient"
11: 
12: export class EntityClient {
13: 	_target: EntityRestInterface
14: 
15: 	constructor(target: EntityRestInterface) {
16: 		this._target = target
17: 	}
18: 
19: 	load<T extends SomeEntity>(
20: 		typeRef: TypeRef<T>,
21: 		id: PropertyType<T, "_id">,
22: 		query?: Dict,
23: 		extraHeaders?: Dict,
24: 		ownerKey?: Aes128Key,
25: 		providedOwnerEncSessionKey?: Uint8Array | null,
26: 	): Promise<T> {
27: 		return this._target.load(typeRef, id, query, extraHeaders, ownerKey, providedOwnerEncSessionKey)
28: 	}
29: 
30: 	async loadAll<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start?: Id): Promise<T[]> {
31: 		const typeModel = await resolveTypeReference(typeRef)
32: 
33: 		if (!start) {
34: 			start = typeModel.values["_id"].type === ValueType.GeneratedId ? GENERATED_MIN_ID : CUSTOM_MIN_ID
35: 		}
36: 
37: 		const elements = await this.loadRange<T>(typeRef, listId, start, RANGE_ITEM_LIMIT, false)
38: 		if (elements.length === RANGE_ITEM_LIMIT) {
39: 			let lastElementId = getLetId(elements[elements.length - 1])[1]
40: 			const nextElements = await this.loadAll<T>(typeRef, listId, lastElementId)
41: 			return elements.concat(nextElements)
42: 		} else {
43: 			return elements
44: 		}
45: 	}
46: 
47: 	async loadReverseRangeBetween<T extends ListElementEntity>(
48: 		typeRef: TypeRef<T>,
49: 		listId: Id,
50: 		start: Id,
51: 		end: Id,
52: 		rangeItemLimit: number = RANGE_ITEM_LIMIT,
53: 	): Promise<{
54: 		elements: T[]
55: 		loadedCompletely: boolean
56: 	}> {
57: 		const typeModel = await resolveTypeReference(typeRef)
58: 		if (typeModel.type !== Type.ListElement) throw new Error("only ListElement types are permitted")
59: 		const loadedEntities = await this._target.loadRange<T>(typeRef, listId, start, rangeItemLimit, true)
60: 		const filteredEntities = loadedEntities.filter((entity) => firstBiggerThanSecond(getElementId(entity), end, typeModel))
61: 
62: 		if (filteredEntities.length === rangeItemLimit) {
63: 			const lastElementId = getElementId(filteredEntities[loadedEntities.length - 1])
64: 			const { elements: remainingEntities, loadedCompletely } = await this.loadReverseRangeBetween<T>(typeRef, listId, lastElementId, end, rangeItemLimit)
65: 			return {
66: 				elements: filteredEntities.concat(remainingEntities),
67: 				loadedCompletely,
68: 			}
69: 		} else {
70: 			return {
71: 				elements: filteredEntities,
72: 				loadedCompletely: wasReverseRangeCompletelyLoaded(rangeItemLimit, loadedEntities, filteredEntities),
73: 			}
74: 		}
75: 	}
76: 
77: 	loadRange<T extends ListElementEntity>(typeRef: TypeRef<T>, listId: Id, start: Id, count: number, reverse: boolean): Promise<T[]> {
78: 		return this._target.loadRange(typeRef, listId, start, count, reverse)
79: 	}
80: 
81: 	/**
82: 	 * load multiple does not guarantee order or completeness of returned elements.
83: 	 */
84: 	loadMultiple<T extends SomeEntity>(
85: 		typeRef: TypeRef<T>,
86: 		listId: Id | null,
87: 		elementIds: Id[],
88: 		providedOwnerEncSessionKeys?: Map<Id, Uint8Array>,
89: 	): Promise<T[]> {
90: 		return this._target.loadMultiple(typeRef, listId, elementIds, providedOwnerEncSessionKeys)
91: 	}
92: 
93: 	setup<T extends SomeEntity>(listId: Id | null, instance: T, extraHeaders?: Dict, options?: EntityRestClientSetupOptions): Promise<Id> {
94: 		return this._target.setup(listId, instance, extraHeaders, options)
95: 	}
96: 
97: 	setupMultipleEntities<T extends SomeEntity>(listId: Id | null, instances: Array<T>): Promise<Array<Id>> {
98: 		return this._target.setupMultiple(listId, instances)
99: 	}
100: 
101: 	update<T extends SomeEntity>(instance: T, ownerKey?: Aes128Key): Promise<void> {
102: 		return this._target.update(instance, ownerKey)
103: 	}
104: 
105: 	erase<T extends SomeEntity>(instance: T): Promise<void> {
106: 		return this._target.erase(instance)
107: 	}
108: 
109: 	async loadRoot<T extends ElementEntity>(typeRef: TypeRef<T>, groupId: Id): Promise<T> {
110: 		const typeModel = await resolveTypeReference(typeRef)
111: 		const rootId = [groupId, typeModel.rootId] as const
112: 		const root = await this.load<RootInstance>(RootInstanceTypeRef, rootId)
113: 		return this.load<T>(typeRef, downcast(root.reference))
114: 	}
115: }
116: 
117: function wasReverseRangeCompletelyLoaded<T extends ListElementEntity>(rangeItemLimit: number, loadedEntities: Array<T>, filteredEntities: Array<T>): boolean {
118: 	if (loadedEntities.length < rangeItemLimit) {
119: 		const lastLoaded = last(loadedEntities)
120: 		const lastFiltered = last(filteredEntities)
121: 
122: 		if (!lastLoaded) {
123: 			return true
124: 		}
125: 
126: 		return lastLoaded === lastFiltered
127: 	}
128: 
129: 	return false
130: }
