		// but if the session key is not propagated, decryption will fail
		const mailDetailsContent = createMailDetails({
			body: createBody(),
			recipients: createRecipients(),
		})
		mailDetailsBlob.details = mailDetailsContent

		// Add entities to the mock
		entityMock.addListInstances(mail)
		entityMock.addBlobInstances(mailDetailsBlob)

		// Override loadMultiple to verify that providedOwnerEncSessionKeys is NOT passed
		// (demonstrating the bug)
		let loadMultipleCalled = false
		let providedSessionKeysWereNull = false
		const originalLoadMultiple = entityMock.loadMultiple.bind(entityMock)

		entityMock.loadMultiple = async function<T>(
			typeRef,
			listId,
			elementIds,
			providedOwnerEncSessionKeys,
		) {
			loadMultipleCalled = true
			// The bug: providedOwnerEncSessionKeys is undefined/null when it shouldn't be
			providedSessionKeysWereNull = providedOwnerEncSessionKeys == null

			// Call the original method
			return originalLoadMultiple(typeRef, listId, elementIds, providedOwnerEncSessionKeys)
		}

		// Call loadMailDetails with the non-legacy mail
		const result = await indexer.loadMailDetails([mail])

		// Verify the load was attempted
		o(loadMultipleCalled).equals(true)(
			"loadMultiple should be called when loading non-legacy mail details",
		)

		// This assertion demonstrates the bug: session keys are not provided
		o(providedSessionKeysWereNull).equals(true)(
			"BUG: providedOwnerEncSessionKeys should be provided to loadMultiple for non-legacy mails, " +
			"but it is null/undefined. This causes decryption to fail.",
		)

		// The mail details would have decryption errors due to missing session key
		o(result.length).equals(1)(
			"loadMailDetails should return one MailWrapper for one input mail",
		)

		// The result should contain the mail details, but with potential decryption issues
		// because the session key was not propagated during batch loading
		const wrapper = result[0]
		o(wrapper).notEquals(null)("MailWrapper should be created")
		o(isSameId(wrapper.mail._id, mail._id)).equals(true)(
			"Wrapped mail should be the non-legacy mail we created",
		)
	})

	o("single mail loading should work correctly with session key propagation", async function () {
		// This test demonstrates that single-mail loading in MailIndexer
		// correctly propagates session keys, but batch loading does not

		const ownerGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const ownerEncSessionKey = encryptKey(ownerGroupKey, sessionKey)

		const mail: Mail = createMail()
		mail._id = ["mail-list-id", "mail-2"]
		mail._ownerGroup = "owner-group-id"
		mail._ownerEncSessionKey = ownerEncSessionKey
		mail.mailDetails = ["maildetails-list-id", "maildetails-blob-2"]
		mail.subject = "Test mail for single load"

		const mailDetailsBlob: MailDetailsBlob = createMailDetailsBlob()
		mailDetailsBlob._id = ["maildetails-list-id", "maildetails-blob-2"]
		mailDetailsBlob._ownerGroup = "owner-group-id"
		mailDetailsBlob.details = createMailDetails({
			body: createBody(),
			recipients: createRecipients(),
		})

		entityMock.addListInstances(mail)
		entityMock.addBlobInstances(mailDetailsBlob)

		// Track if session keys are passed when loading via load() (single entity)
		let singleLoadSessionKeysPassed = false
		const originalLoad = entityMock.load.bind(entityMock)

		entityMock.load = async function(typeRef, id, query, headers, ownerKey, providedOwnerEncSessionKey) {
			if (providedOwnerEncSessionKey != null) {
				singleLoadSessionKeysPassed = true
			}
			return originalLoad(typeRef, id, query, headers, ownerKey, providedOwnerEncSessionKey)
		}

		// Single mail loading via EntityClient should pass session key
		// (This works correctly in the actual code at MailIndexer:154-155)
		const entityClient = new EntityClient(downcast(entityMock))
		const loaded = await entityClient.load(
			MailDetailsBlobTypeRef,
			mail.mailDetails as any,
			undefined,
			undefined,
			undefined,
			mail._ownerEncSessionKey, // Session key IS passed in single load
		)

		o(singleLoadSessionKeysPassed).equals(true)(
			"Single entity load correctly passes providedOwnerEncSessionKey",
		)
	})

	o("loadMailDetails batch loading is missing session key propagation parameter", async function () {
		// Direct test showing that loadMailDetails calls loadInChunks
		// which calls loadMultiple WITHOUT the providedOwnerEncSessionKeys parameter

		const ownerGroupKey = aes128RandomKey()
		const sessionKey = aes128RandomKey()
		const ownerEncSessionKey = encryptKey(ownerGroupKey, sessionKey)

		// Create three non-legacy mails
		const mails: Mail[] = []
		for (let i = 0; i < 3; i++) {
			const mail = createMail()
			mail._id = ["mail-list-id", `mail-batch-${i}`]
			mail._ownerGroup = "owner-group-id"
			mail._ownerEncSessionKey = ownerEncSessionKey
			mail.mailDetails = ["maildetails-list-id", `maildetails-blob-batch-${i}`]
			mail.subject = `Batch mail ${i}`
			mails.push(mail)

			const mailDetailsBlob: MailDetailsBlob = createMailDetailsBlob()
			mailDetailsBlob._id = ["maildetails-list-id", `maildetails-blob-batch-${i}`]
			mailDetailsBlob._ownerGroup = "owner-group-id"
			mailDetailsBlob.details = createMailDetails({
				body: createBody(),
				recipients: createRecipients(),
			})

			entityMock.addListInstances(mail)
			entityMock.addBlobInstances(mailDetailsBlob)
		}

		// Track how loadMultiple is called
		const loadMultipleCalls: Array<{
			elementIds: string[]
			providedOwnerEncSessionKeys: any
		}> = []

		const originalLoadMultiple = entityMock.loadMultiple.bind(entityMock)
		entityMock.loadMultiple = async function(
			typeRef,
			listId,
			elementIds,
			providedOwnerEncSessionKeys,
		) {
			loadMultipleCalls.push({
				elementIds: elementIds as any,
				providedOwnerEncSessionKeys,
			})
			return originalLoadMultiple(typeRef, listId, elementIds, providedOwnerEncSessionKeys)
		}

		// Load mail details for all three mails at once
		const results = await indexer.loadMailDetails(mails)

		// Verify results
		o(results.length).equals(3)("Should load all three mails")

		// Verify the bug: loadMultiple was called but WITHOUT providedOwnerEncSessionKeys
		o(loadMultipleCalls.length).equals(1)("loadMultiple should be called once for batch loading")

		const call = loadMultipleCalls[0]
		o(call.elementIds.length).equals(3)(
			"Should load all three maildetails blobs in a single batch",
		)

		// This is the BUG: providedOwnerEncSessionKeys is null/undefined
		o(call.providedOwnerEncSessionKeys == null).equals(true)(
			"BUG: Session keys should have been provided to loadMultiple as a Map, " +
			"but they are null/undefined. This causes MailDetailsBlob decryption to fail.",
		)
	})
})

// Helper function to compare entity IDs
function isSameId(id1: IdTuple | Id, id2: IdTuple | Id): boolean {
	if (Array.isArray(id1) && Array.isArray(id2)) {
		return id1[0] === id2[0] && id1[1] === id2[1]
	}
	return id1 === id2
}

